from __future__ import annotations

from dataclasses import dataclass
from decimal import Decimal
from enum import Enum


MoneyInput = Decimal | int | str


class ShoppingCartError(Exception):
    """Base exception for shopping cart errors."""


class InvalidProductNameError(ShoppingCartError):
    """Raised when a product name is missing or invalid."""


class InvalidUnitPriceError(ShoppingCartError):
    """Raised when a unit price is invalid."""


class InvalidQuantityError(ShoppingCartError):
    """Raised when an item quantity is invalid."""


class ItemNotFoundError(ShoppingCartError):
    """Raised when an item does not exist in the cart."""


class InvalidDiscountError(ShoppingCartError):
    """Raised when a discount value is invalid."""


class DiscountType(Enum):
    """Supported discount strategies."""

    PERCENTAGE = "percentage"
    FLAT = "flat"


@dataclass(frozen=True, slots=True)
class CartItem:
    """Represents a single item in a shopping cart."""

    product_name: str
    unit_price: Decimal
    quantity: int

    @property
    def total_price(self) -> Decimal:
        """Return the total price for this item before discounts."""
        return self.unit_price * self.quantity


@dataclass(frozen=True, slots=True)
class Discount:
    """Represents a cart-level discount."""

    discount_type: DiscountType
    amount: Decimal


class ShoppingCart:
    """Manage shopping cart items, discounts, and total calculations."""

    def __init__(self) -> None:
        """Initialize an empty shopping cart."""
        self._items: dict[str, CartItem] = {}
        self._discount: Discount | None = None

    def add_item(
        self,
        product_name: str,
        unit_price: MoneyInput,
        quantity: int = 1,
    ) -> None:
        """Add an item to the cart or increase its quantity if it already exists."""
        normalized_product_name = self._validate_product_name(product_name)
        validated_unit_price = self._validate_unit_price(unit_price)
        validated_quantity = self._validate_quantity(quantity)

        existing_item = self._items.get(normalized_product_name)
        if existing_item is None:
            self._items[normalized_product_name] = CartItem(
                product_name=normalized_product_name,
                unit_price=validated_unit_price,
                quantity=validated_quantity,
            )
            return

        self._items[normalized_product_name] = CartItem(
            product_name=existing_item.product_name,
            unit_price=validated_unit_price,
            quantity=existing_item.quantity + validated_quantity,
        )

    def remove_item(self, product_name: str) -> None:
        """Remove an item from the cart by product name."""
        normalized_product_name = self._validate_product_name(product_name)
        self._get_existing_item(normalized_product_name)
        del self._items[normalized_product_name]

    def update_quantity(self, product_name: str, quantity: int) -> None:
        """Update the quantity of an existing cart item."""
        normalized_product_name = self._validate_product_name(product_name)
        validated_quantity = self._validate_quantity(quantity)
        existing_item = self._get_existing_item(normalized_product_name)

        self._items[normalized_product_name] = CartItem(
            product_name=existing_item.product_name,
            unit_price=existing_item.unit_price,
            quantity=validated_quantity,
        )

    def calculate_subtotal(self) -> Decimal:
        """Calculate the cart subtotal before discounts."""
        return sum((item.total_price for item in self._items.values()), Decimal("0"))

    def apply_percentage_discount(self, percentage: MoneyInput) -> None:
        """Apply a percentage discount to the cart."""
        discount_percentage = self._to_decimal(percentage, "percentage discount")

        if discount_percentage < Decimal("0") or discount_percentage > Decimal("100"):
            raise InvalidDiscountError(
                "Percentage discount must be between 0 and 100 inclusive."
            )

        self._discount = Discount(
            discount_type=DiscountType.PERCENTAGE,
            amount=discount_percentage,
        )

    def apply_flat_discount(self, amount: MoneyInput) -> None:
        """Apply a flat discount amount to the cart."""
        discount_amount = self._to_decimal(amount, "flat discount")

        if discount_amount < Decimal("0"):
            raise InvalidDiscountError("Flat discount cannot be negative.")

        self._discount = Discount(
            discount_type=DiscountType.FLAT,
            amount=discount_amount,
        )

    def calculate_total(self) -> Decimal:
        """Calculate the final cart total after discounts."""
        subtotal = self.calculate_subtotal()

        if self._discount is None:
            return subtotal

        if self._discount.discount_type is DiscountType.PERCENTAGE:
            discount_amount = subtotal * self._discount.amount / Decimal("100")
        else:
            discount_amount = self._discount.amount

        return max(subtotal - discount_amount, Decimal("0"))

    def list_items(self) -> list[CartItem]:
        """Return all cart items with their details."""
        return list(self._items.values())

    def clear(self) -> None:
        """Remove all items and discounts from the cart."""
        self._items.clear()
        self._discount = None

    def _get_existing_item(self, product_name: str) -> CartItem:
        item = self._items.get(product_name)
        if item is None:
            raise ItemNotFoundError(f"Product '{product_name}' is not in the cart.")
        return item

    @staticmethod
    def _validate_product_name(product_name: str) -> str:
        if not isinstance(product_name, str):
            raise InvalidProductNameError("Product name must be a string.")

        normalized_product_name = product_name.strip()
        if not normalized_product_name:
            raise InvalidProductNameError("Product name cannot be empty.")

        return normalized_product_name

    @classmethod
    def _validate_unit_price(cls, unit_price: MoneyInput) -> Decimal:
        validated_unit_price = cls._to_decimal(unit_price, "unit price")

        if validated_unit_price < Decimal("0"):
            raise InvalidUnitPriceError("Unit price cannot be negative.")

        return validated_unit_price

    @staticmethod
    def _validate_quantity(quantity: int) -> int:
        if not isinstance(quantity, int):
            raise InvalidQuantityError("Quantity must be an integer.")

        if quantity <= 0:
            raise InvalidQuantityError("Quantity must be greater than zero.")

        return quantity

    @staticmethod
    def _to_decimal(amount: MoneyInput, field_name: str) -> Decimal:
        if isinstance(amount, bool):
            raise InvalidDiscountError(f"{field_name.capitalize()} must be numeric.")

        if isinstance(amount, float):
            raise InvalidDiscountError(
                f"{field_name.capitalize()} must be provided as Decimal, int, or str."
            )

        try:
            return Decimal(str(amount))
        except Exception as conversion_error:
            raise InvalidDiscountError(
                f"{field_name.capitalize()} must be a valid decimal value."
            ) from conversion_error
